import requests

FLOWISE_URL = "http://localhost:3000"
CHATFLOW_ID = "your-chatflow-uuid"

response = requests.post(
    f"{FLOWISE_URL}/api/v1/prediction/{CHATFLOW_ID}",
    json={
        "question": "What are the main points of the uploaded document?",
        "overrideConfig": {
            "temperature": 0.3,
        },
    },
)
print(response.json()["text"])

// Flowise Custom Tool node — JavaScript function the agent can call
// Configured in the Custom Tool node's "JavaScript Function" field

const fetch = require('node-fetch');

// $vars contains the input arguments declared in the tool schema
const { ticketId } = $vars;

const resp = await fetch(
  `https://api.helpdesk.example.com/tickets/${ticketId}`,
  { headers: { Authorization: `Bearer ${process.env.HELPDESK_API_KEY}` } }
);
const data = await resp.json();

return JSON.stringify({
  status: data.status,
  assignee: data.assignee?.name,
  createdAt: data.created_at,
});

# Pass a sessionId to maintain conversation history across API calls
import requests

SESSION_ID = "user-42-session-7"  # unique per user/conversation

for turn_input in ["Hi!", "What was my first message?"]:
    resp = requests.post(
        "http://localhost:3000/api/v1/prediction/your-chatflow-uuid",
        json={
            "question": turn_input,
            "overrideConfig": {
                "sessionId": SESSION_ID,
            },
        },
    )
    print(f"User: {turn_input}")
    print(f"Bot:  {resp.json()['text']}")
    print()

// Multi-Agent Supervisor in Flowise (Sequential Agent nodes)
// Canvas layout:
// User → Supervisor Agent → [Research Agent, Writer Agent] → Final Response

// Supervisor system prompt (set in the Supervisor Agent node):
You are a research coordinator.
Given a topic, first call the Research Agent to gather facts,
then call the Writer Agent to produce a 3-paragraph summary.
Available agents: research_agent, writer_agent

// Research Agent system prompt:
You are a research specialist. Given a topic, return 5 key facts.
Available tools: web_search, wikipedia_lookup

// Writer Agent system prompt:
You are a concise technical writer.
Given research facts, produce a 3-paragraph summary in plain English.
